import java.util.*;
import java.util.regex.*;

{{solution}}

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextLine()) return;
        String line = sc.nextLine();
        int target = 0;
        Matcher tm = Pattern.compile("target\\s*=\\s*(-?\\d+)").matcher(line);
        if (tm.find()) target = Integer.parseInt(tm.group(1));
        Matcher nm = Pattern.compile("\\[([^\\]]*)\\]").matcher(line);
        List<Integer> list = new ArrayList<>();
        if (nm.find() && !nm.group(1).trim().isEmpty()) {
            for (String s : nm.group(1).split(",")) {
                list.add(Integer.parseInt(s.trim()));
            }
        }
        int[] nums = list.stream().mapToInt(i -> i).toArray();
        Solution solution = new Solution();
        int[] res = solution.twoSum(nums, target);
        if (res == null || res.length < 2) System.out.println("None");
        else System.out.println("[" + res[0] + ", " + res[1] + "]");
        System.out.flush();
    }
}

